/**
 * Superset Bridge Library v2.0 (2026)
 *
 * Reference JS file. This is the standalone web-server version of the bridge.
 * When running inside Flutter via loadData(), the logic is inlined directly
 * into the HTML generated by SupersetBridgeHtmlContent.generate().
 *
 * ## How dark mode works
 *
 *   Superset embeds via a cross-origin <iframe>. Injecting CSS into the
 *   iframe is blocked by the browser (SecurityError). setThemeConfig() does
 *   not exist on the embedDashboard() result.
 *
 *   Instead, a CSS visual filter is applied to the MOUNT DIV in the parent
 *   document — no cross-origin access needed because we own the parent HTML:
 *
 *     body.dark #superset-mount { filter: invert(1) hue-rotate(180deg); }
 *
 *   invert(1) flips brightness (white↔black).
 *   hue-rotate(180deg) spins hues so colours land roughly where they started.
 *   Net effect: clean visual dark mode for charts and tables.
 *
 *   updateUI() toggles the body class — instant, no reload, no flash.
 *
 * ## Public entry-points
 *
 *   SupersetBridge.initWithTokenFetch(uuid, domain, theme, siteIds,
 *                                     hideTitle, filtersExpanded, urlParamsRefresh)
 *     → fetches guest token from <domain>/guest-token?dashboard_id=<uuid>
 *
 *   SupersetBridge.init(uuid, domain, token, theme, siteIds,
 *                       hideTitle, filtersExpanded, urlParamsRefresh)
 *     → token supplied directly by the caller
 *
 *   SupersetBridge.updateUI(theme)
 *     → 'dark' | 'light' — called from Flutter via evaluateJavascript()
 */

window.SupersetBridge = {
  dashboard: null,

  // ── Token helper ──────────────────────────────────────────────────────────

  _fetchToken: async function (domain, uuid) {
    const url = domain + '/guest-token?dashboard_id=' + encodeURIComponent(uuid);
    const resp = await fetch(url);
    if (!resp.ok) throw new Error('Token fetch failed: HTTP ' + resp.status);
    const data = await resp.json();
    return data.token;
  },

  // ── Public API ────────────────────────────────────────────────────────────

  initWithTokenFetch: async function (
    uuid, domain, theme,
    siteIds, hideTitle, filtersExpanded, urlParamsRefresh
  ) {
    try {
      const token = await this._fetchToken(domain, uuid);
      await this._embed(uuid, domain, token, theme, siteIds, hideTitle, filtersExpanded, urlParamsRefresh);
    } catch (e) {
      console.error('[SupersetBridge] ❌ initWithTokenFetch failed:', e);
      this._showError('Failed to load dashboard: ' + e.message);
    }
  },

  init: async function (
    uuid, domain, token, theme,
    siteIds, hideTitle, filtersExpanded, urlParamsRefresh
  ) {
    try {
      await this._embed(uuid, domain, token, theme, siteIds, hideTitle, filtersExpanded, urlParamsRefresh);
    } catch (e) {
      console.error('[SupersetBridge] ❌ init failed:', e);
      this._showError('Failed to load dashboard: ' + e.message);
    }
  },

  /**
   * Toggle dark/light mode by switching the body CSS class.
   * No cross-origin access — operates on the parent document only.
   * @param {string} theme - 'dark' | 'light'
   */
  updateUI: function (theme) {
    const isDark = theme === 'dark';
    document.body.classList.toggle('dark', isDark);
    document.body.classList.toggle('light', !isDark);
    console.log('[SupersetBridge] ✅ Theme → ' + theme);
  },

  // ── Private ───────────────────────────────────────────────────────────────

  _embed: async function (
    uuid, domain, token, theme,
    siteIds, hideTitle, filtersExpanded, urlParamsRefresh
  ) {
    if (typeof supersetEmbeddedSdk === 'undefined') {
      console.error('[SupersetBridge] ❌ Superset SDK not loaded');
      this._showError('Superset SDK failed to load. Check network.');
      return;
    }

    const mountPoint = document.getElementById('superset-mount');
    if (!mountPoint) {
      console.error('[SupersetBridge] ❌ Mount point #superset-mount not found');
      return;
    }

    this._showLoading(true);

    const urlParams = {};
    if (urlParamsRefresh) urlParams.refresh = true;
    urlParams.theme = theme;
    if (siteIds && Array.isArray(siteIds) && siteIds.length > 0) {
      urlParams.siteId = siteIds;
    }

    try {
      this.dashboard = await supersetEmbeddedSdk.embedDashboard({
        id: uuid,
        supersetDomain: domain,
        mountPoint: mountPoint,
        fetchGuestToken: () => Promise.resolve(token),
        dashboardUiConfig: {
          hideTitle: hideTitle,
          standalone: true,
          filters: { expanded: filtersExpanded },
          urlParams: urlParams,
        },
        iframeSandboxExtras: ['allow-top-navigation', 'allow-popups-to-escape-sandbox'],
      });
      this._showLoading(false);
      this.updateUI(theme);
      console.log('[SupersetBridge] ✅ Dashboard ready');
    } catch (e) {
      this._showLoading(false);
      console.error('[SupersetBridge] ❌ embedDashboard failed:', e);
      this._showError('Failed to embed dashboard: ' + e.message);
    }
  },

  _showLoading: function (show) {
    const el = document.getElementById('_bridge_loading');
    if (el) el.className = show ? '' : 'hidden';
  },

  _showError: function (message) {
    const el = document.getElementById('_bridge_error');
    if (el) { el.className = 'visible'; el.textContent = message; }
    this._showLoading(false);
  },
};
